import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { TaskProvider } from './contexts/TaskContext';
import Layout from './components/Layout/Layout';
import Dashboard from './pages/Dashboard';
import TestDashboard from './TestDashboard';
import CustomerDashboard from './pages/CustomerDashboard';
import BranchStaffDashboard from './pages/BranchStaffDashboard';
import ContactCenterDashboard from './pages/ContactCenterDashboard';
import MarketingDashboard from './pages/MarketingDashboard';
import CMDDashboard from './pages/CMDDashboard';
import AuditDashboard from './pages/AuditDashboard';
import WorkUnitDashboard from './pages/WorkUnitDashboard';
import ServiceQualityDashboard from './pages/ServiceQualityDashboard';
import TaskDetail from './pages/TaskDetail';
import ComplaintRegistration from './pages/ComplaintRegistration';
import TestConnection from './TestConnection';

function App() {
  return (
    <TaskProvider>
      <Router>
        <Layout>
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/customer" element={<CustomerDashboard />} />
            <Route path="/branch-staff" element={<BranchStaffDashboard />} />
            <Route path="/contact-center" element={<ContactCenterDashboard />} />
            <Route path="/marketing" element={<MarketingDashboard />} />
            <Route path="/cmd" element={<CMDDashboard />} />
            <Route path="/audit" element={<AuditDashboard />} />
            <Route path="/work-unit" element={<WorkUnitDashboard />} />
            <Route path="/service-quality" element={<ServiceQualityDashboard />} />
            <Route path="/task/:taskId" element={<TaskDetail />} />
            <Route path="/complaint-registration" element={<ComplaintRegistration />} />
            <Route path="/test-connection" element={<TestConnection />} />
          </Routes>
        </Layout>
      </Router>
    </TaskProvider>
  );
}

export default App;
